@Get('static/list')
  @OnlyIdentity(IdentityRole.Admin)
  @SuccessResponse('Get file list succeeded')
  async getStaticFileList(@RequestContext() { query }: IRequestContext) {
    const minLimit = 200
    const numberLimit = Number(query.limit)
    const limit = Number.isInteger(numberLimit) ? numberLimit : minLimit
    const result = await this.s3Service.getFileList({
      limit: limit < minLimit ? minLimit : limit,
      prefix: query.prefix,
      startAfter: query.startAfter,
      delimiter: query.delimiter,
      region: APP_CONFIG.S3_STORAGE.s3StaticFileRegion,
      bucket: APP_CONFIG.S3_STORAGE.s3StaticFileBucket
    })

    return {
      ...result,
      files: result.files.map((file) => ({
        ...file,
        url: `${APP_CONFIG.APP_BIZ.STATIC_URL}/${file.key}`,
        lastModified: file.lastModified?.getTime()
      }))
    }
  }

async deleteItems(keys: string[], options?: IAwsS3Options): Promise<void> {
    if (!this.isInitialized()) {
        this.logger.warn(
            'AWS S3 credentials not configured. S3 functionalities will be disabled.'
        );

        return;
    }

    if (keys.some(e => e.startsWith('/'))) {
        throw new Error('Keys should not start with "/"');
    }

    const config = this.config.get(
        options?.access ?? EnumAwsS3Accessibility.public
    );
    const obj: ObjectIdentifier[] = keys.map((val: string) => ({
        Key: val,
    }));
    const command: DeleteObjectsCommand = new DeleteObjectsCommand({
        Bucket: config.bucket,
        Delete: { Objects: obj },
    });

    await this.s3Client.send<
        DeleteObjectsCommandInput,
        DeleteObjectsCommandOutput
    >(command);
}

mapPresign(
    { key, size }: AwsS3PresignRequestDto,
    options?: IAwsS3Options
): AwsS3Dto {
    if (key.startsWith('/')) {
        throw new Error('Key should not start with "/"');
    }

    const accessibility = options?.access ?? EnumAwsS3Accessibility.public;
    const config = this.config.get(accessibility);
    const { pathWithFilename, extension, mime } =
        this.getFileInfoFromKey(key);

    return {
        bucket: config.bucket,
        key,
        completedUrl: `${config.baseUrl}${pathWithFilename}`,
        cdnUrl:
            config.cdnUrl && config.cdnUrl !== ''
                ? `${config.cdnUrl}${pathWithFilename}`
                : undefined,
        extension,
        size,
        mime,
        access: accessibility,
    };
}

async function waitForServer(url: string, timeoutMs = 5_000): Promise<void> {
  const start = Date.now();
  // Use global fetch if available (Node 18+). If not, just wait a bit.
  const hasFetch = typeof (globalThis as any).fetch === 'function';

  while (Date.now() - start < timeoutMs) {
    try {
      if (hasFetch) {
        const res = await (globalThis as any).fetch(url, { method: 'GET' });
        if (res && (res.status === 200 || res.status === 404)) return;
      } else {
        // best-effort fallback
        await sleep(250);
        return;
      }
    } catch {
      // server not ready yet
    }
    await sleep(100);
  }

  throw new Error(`Server did not become ready in ${timeoutMs}ms: ${url}`);
}

