public getAllAndMerge<TResult extends any[] | object = any[], TKey = any>(
  metadataKeyOrDecorator: TKey,
  targets: (Type<any> | Function)[],
): TResult {
  const metadataCollection = this.getAll<any[], TKey>(
    metadataKeyOrDecorator,
    targets,
  ).filter(item => item !== undefined);

  if (isEmpty(metadataCollection)) {
    return metadataCollection as TResult;
  }
  if (metadataCollection.length === 1) {
    const value = metadataCollection[0];
    if (isObject(value)) {
      return value as TResult;
    }
    return metadataCollection as TResult;
  }
  return metadataCollection.reduce((a, b) => {
    if (Array.isArray(a)) {
      return a.concat(b);
    }
    if (isObject(a) && isObject(b)) {
      return {
        ...a,
        ...b,
      };
    }
    return [a, b];
  });
}

protected validatePrimitive(originalValue: any, index?: number) {
  if (this.options.items === Number) {
    const value =
      originalValue !== null && originalValue !== '' ? +originalValue : NaN;
    if (isNaN(value)) {
      throw this.exceptionFactory(
        `${isUndefined(index) ? '' : `[${index}] `}item must be a number`,
      );
    }
    return value;
  } else if (this.options.items === String) {
    if (!isString(originalValue)) {
      return `${originalValue}`;
    }
  } else if (this.options.items === Boolean) {
    if (typeof originalValue !== 'boolean') {
      throw this.exceptionFactory(
        `${
          isUndefined(index) ? '' : `[${index}] `
        }item must be a boolean value`,
      );
    }
  }
  return originalValue;
}

public async intercept<TContext extends string = ContextType>(
  interceptors: NestInterceptor[],
  args: unknown[],
  instance: Controller,
  callback: (...args: unknown[]) => unknown,
  next: () => Promise<unknown>,
  type?: TContext,
): Promise<unknown> {
  if (isEmpty(interceptors)) {
    return next();
  }
  const context = this.createContext(args, instance, callback);
  context.setType<TContext>(type!);

  const nextFn = async (i = 0) => {
    if (i >= interceptors.length) {
      return defer(AsyncResource.bind(() => this.transformDeferred(next)));
    }
    const handler: CallHandler = {
      handle: () =>
        defer(AsyncResource.bind(() => nextFn(i + 1))).pipe(mergeAll()),
    };
    return interceptors[i].intercept(context, handler);
  };
  return defer(() => nextFn()).pipe(mergeAll());
}

export function main(options: SubAppOptions): Rule {
  const appName = getAppNameFromPackageJson();
  options = transform(options);
  return chain([
    updateTsConfig(),
    updatePackageJson(options, appName),
    (tree, context) =>
      isMonorepo(tree)
        ? noop()(tree, context)
        : chain([
            branchAndMerge(mergeWith(generateWorkspace(options, appName))),
            moveDefaultAppToApps(options.path, appName, options.sourceRoot),
          ])(tree, context),
    addAppsToCliOptions(options.path, options.name, appName),
    branchAndMerge(mergeWith(generate(options))),
    options.format === true ? formatFiles() : noop(),
  ]);
}

async getRoleDept(roleId: number) {
  const role = await this.prisma.sysRole.findUnique({
    include: {
      depts: true,
    },
    where: {
      roleId,
      delFlag: '0',
    },
  });
  const { depts, deptCheckStrictly } = role;
  if (!deptCheckStrictly) return depts.map((menu) => menu.deptId);
  const filterRole = depts.filter((dept) => {
    return !depts.some(
      (dept2) =>
        dept.deptId != dept2.deptId &&
        ` ${dept2.ancestors}`.includes(`,${dept.deptId},`),
    );
  });
  return filterRole.map((menu) => menu.deptId);
}

async misfirePolicy(jobArr: Job[]) {
  //查询所有数据库还在的任务
  jobArr = await this.findByIds(jobArr.map((item) => item.jobId));
  // 立即执行的
  const immediately: Job[] = [];
  // 执行一次的
  const executeOnce: Job[] = [];
  jobArr.forEach((job) => {
    if (job.misfirePolicy == '1') {
      immediately.push(job);
    }
    if (
      job.misfirePolicy == '2' &&
      !executeOnce.find((job2) => job.jobId == job2.jobId)
    ) {
      executeOnce.push(job);
    }
  });
  await Promise.all(
    [...immediately, ...executeOnce].map(async (job) => await this.once(job)),
  );
}

