async uploadProfilePicture(
  id: number,
  file: Files[0],
): Promise<Expose<User>> {
  if (file.size > 25000000) throw new Error(FILE_TOO_LARGE);
  if (!this.configService.get<string>('s3.profilePictureBucket'))
    throw new InternalServerErrorException('Profile picture bucket not set');
  const { Location } = await this.s3Service.upload(
    `picture-${id}-${this.tokensService.generateUuid()}${extname(
      file.originalname,
    )}`,
    file.buffer,
    this.configService.get<string>('s3.profilePictureBucket'),
    true,
  );
  return this.prisma.user.update({
    where: { id },
    data: {
      profilePictureUrl: Location.replace(
        `${this.configService.get<string>(
          's3.profilePictureBucket',
        )}.s3.${this.configService.get<string>('s3.region')}.amazonaws.com`,
        this.configService.get<string>('s3.profilePictureCdnHostname'),
      ),
    },
  });
}

export function isLogLevelEnabled(
  targetLevel: LogLevel,
  logLevels: LogLevel[] | undefined,
): boolean {
  if (!logLevels || (Array.isArray(logLevels) && logLevels?.length === 0)) {
    return false;
  }
  if (logLevels.includes(targetLevel)) {
    return true;
  }

  let highestLogLevelValue = -Infinity;
  for (const level of logLevels) {
    const v = LOG_LEVEL_VALUES[level];
    if (v > highestLogLevelValue) highestLogLevelValue = v;
  }

  const targetLevelValue = LOG_LEVEL_VALUES[targetLevel];
  return targetLevelValue >= highestLogLevelValue;
}

export function diff(x: Date | string, y: Date | string): IDifference {
  x = _To_date(x);
  y = _To_date(y);

  // FIRST DIFFERENCES
  const ret: IDifference = {
    year: x.getFullYear() - y.getFullYear(),
    month: x.getMonth() - y.getMonth(),
    date: x.getDate() - y.getDate(),
  };

  //----
  // HANDLE NEGATIVE ELEMENTS
  //----
  // DATE
  if (ret.date < 0) {
    const last: number = lastDate(y.getFullYear(), y.getMonth());

    --ret.month;
    ret.date = x.getDate() + (last - y.getDate());
  }

  // MONTH
  if (ret.month < 0) {
    --ret.year;
    ret.month = 12 + ret.month;
  }
  return ret;
}

