async log(to: string, code: string, ip: string) {
  const getRemainTime = () => {
    const now = dayjs()
    return now.endOf('day').diff(now, 'second')
  }

  await this.redis.set(`captcha:${to}`, code, 'EX', 60 * 5)

  const limitCountOfDay = await this.redis.get(`captcha:${to}:limit-day`)
  const ipLimitCountOfDay = await this.redis.get(`ip:${ip}:send:limit-day`)

  await this.redis.set(`ip:${ip}:send:limit`, 1, 'EX', 60)
  await this.redis.set(`captcha:${to}:limit`, 1, 'EX', 60)
  await this.redis.set(
    `captcha:${to}:send:limit-count-day`,
    limitCountOfDay,
    'EX',
    getRemainTime(),
  )
  await this.redis.set(
    `ip:${ip}:send:limit-count-day`,
    ipLimitCountOfDay,
    'EX',
    getRemainTime(),
  )
}

updateEventTriggerMeta = (
  moduleConfig: HasuraModuleConfig,
  eventHandlerConfigs: TrackedHasuraEventHandlerConfig[],
) => {
  const { managedMetaDataConfig } = moduleConfig;

  const { metadataVersion = 'v2' } = moduleConfig.managedMetaDataConfig!;

  if (!managedMetaDataConfig) {
    throw new Error(MISSING_META_CONFIG);
  }

  if (metadataVersion === 'v2') {
    updateEventTriggerMetaV2(moduleConfig, eventHandlerConfigs);
  } else if (metadataVersion === 'v3') {
    updateEventTriggerMetaV3(moduleConfig, eventHandlerConfigs);
  } else {
    throw new Error(`Invalid Hasura metadata version: ${metadataVersion}`);
  }
}

@UseGuards(GqlAuthGuard)
  @Resource({
    name: 'access_token',
    identify: 'access_token',
    roles: ['owner', 'admin', 'developer'],
    action: 'read',
  })
  @Query(() => [AccessToken], { nullable: true })
  async accessTokens(
    @Args() input: AccessTokenFilterArgs,
    @Context() ctx: GqlContext,
  ): Promise<AccessToken[]> {
    let t;
    let r;
    if (input?.where) {
      const { tenantId, ...rest } = input?.where;
      t = tenantId;
      r = rest;
    }

    const res = await ctx?.rpc?.accessToken?.svc
      .findAccess(
        {
          filter: JSON.stringify(r),
          tenantId: t,
        },
        setRpcContext(ctx),
      )
      .toPromise();
    return (res.accessToken as unknown) as AccessToken[];
  }

function use(
  this: unknown,
  url:
    | string
    | null
    | MiddlewareFn<Req, Res, Ctx>
    | MiddlewareFn<Req, Res, Ctx>[],
  f?: MiddlewareFn<Req, Res, Ctx> | MiddlewareFn<Req, Res, Ctx>[],
) {
  if (f === undefined) {
    f = url as MiddlewareFn<Req, Res, Ctx> | MiddlewareFn<Req, Res, Ctx>[];
    url = null;
  }

  let regexp: RegExp | undefined;
  if (typeof url === 'string') {
    const pathRegExp = pathToRegexp(sanitizePrefixUrl(url) as Path, {
      end: false,
    });
    regexp = pathRegExp.regexp;
  }

  if (Array.isArray(f)) {
    for (const val of f) {
      middlewares.push({ regexp, fn: val });
    }
  } else {
    middlewares.push({ regexp, fn: f });
  }

  return this;
}
